import re
from pathlib import Path

import pytest

AC_UID = "ae1de0c57d012c17"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
DEV_MD = REPO_ROOT / "commands" / "dev.md"


def _slice(text: str, start_re: str, end_re: str) -> str:
    m_start = re.search(start_re, text, re.MULTILINE)
    assert m_start, f"start anchor {start_re!r} not found in commands/dev.md"
    rest = text[m_start.start():]
    m_end = re.search(end_re, rest[1:], re.MULTILINE)
    end_pos = m_end.start() + 1 if m_end else len(rest)
    return rest[:end_pos]


def test_AC_05():
    """
    GIVEN: commands/dev.md is read as text
    WHEN:  the Step 11 QA-dispatch prompt block AND the Dev-handoff text block (~line 666) are inspected separately (each scope-anchored)
    THEN:  BOTH the QA-dispatch block and the Dev-handoff block contain a per-task manifest-path line (tests/generated/<task_id>/manifest.json); unqualified global-path references are forbidden in both scopes (global is allowed only when annotated '(index)' or '(global)')
    """
    assert DEV_MD.is_file(), f"missing: {DEV_MD}"
    src = DEV_MD.read_text(encoding="utf-8")

    step11 = _slice(src, r"^### Step 11:", r"^### Step 12:")
    assert "tests/generated/<task_id>/manifest.json" in step11, (
        "commands/dev.md Step 11 missing per-task manifest path"
    )
    bad = re.search(r"tests/generated/manifest\.json(?!\s*\((?:index|global))", step11)
    assert bad is None, (
        f"commands/dev.md Step 11 has unqualified global manifest reference: {bad.group(0)!r}"
    )

    dev_handoff = _slice(
        src,
        r"Generated tests \(when test-writer ran\):",
        r"Write your implementation report",
    )
    assert "tests/generated/<task_id>/manifest.json" in dev_handoff, (
        "commands/dev.md Dev-handoff missing per-task manifest path"
    )
    bad2 = re.search(r"tests/generated/manifest\.json(?!\s*\((?:index|global))", dev_handoff)
    assert bad2 is None, (
        f"commands/dev.md Dev-handoff has unqualified global manifest reference: {bad2.group(0)!r}"
    )
